const AIRTABLE_TOKEN = 'YOUR_TOKEN';
const BASE_ID = 'apprJuNN7cJybIziP';
const WEBHOOK_ID = 'ach1yRrkXAbUndxBU'; // ← Paste your webhook ID here

const TABLE_CONFIG = [
  {
    tableLabel: 'Products',
    sourceBaseId: 'apprJuNN7cJybIziP',
    sourceTableId: 'tbl3ONmeGLiaMoeRR',
    backupBaseId: 'appAOHsB7wbh1oc7w',
    backupTableId: 'tblMonZkhAGAqge3V',
    fields: ['Name', 'Status', 'Price', 'Notes']
  },
  {
    tableLabel: 'Orders',
    sourceBaseId: 'apprJuNN7cJybIziP',
    sourceTableId: 'tblTIFYe8RUiMuWJf',
    backupBaseId: 'appAOHsB7wbh1oc7w',
    backupTableId: 'tbl2UhrlXMlygYrfg',
    fields: ['Name', 'Status', 'Customer', 'Amount'] // ✅ Fixed fields
  },
  {
    tableLabel: 'Customers',
    sourceBaseId: 'apprJuNN7cJybIziP',
    sourceTableId: 'tblp1XLLYbmWEV4DR',
    backupBaseId: 'appAOHsB7wbh1oc7w',
    backupTableId: 'tbldyD5a4q5v9huBN',
    fields: ['Name', 'Status', 'Phone', 'Email']
  }
];

// ============================================================
// API CALL 1 — Immediately fetch payloads
// ============================================================
let changesResponse;
try {
  changesResponse = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.airtable.com/v0/bases/${BASE_ID}/webhooks/${WEBHOOK_ID}/payloads`,
    headers: { 'Authorization': `Bearer ${AIRTABLE_TOKEN}` },
    json: true
  });
} catch (err) {
  throw new Error(`Failed to fetch webhook payloads: ${err.message}`);
}

const payloads = changesResponse.payloads || [];
const cursor = changesResponse.cursor;

// ============================================================
// API CALL 2 — Acknowledge IMMEDIATELY
// This makes all other parallel executions skip themselves
// ============================================================
if (cursor) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `https://api.airtable.com/v0/bases/${BASE_ID}/webhooks/${WEBHOOK_ID}/payloads/acknowledge`,
      headers: {
        'Authorization': `Bearer ${AIRTABLE_TOKEN}`,
        'Content-Type': 'application/json'
      },
      body: { cursor },
      json: true
    });
  } catch (err) {
    console.error('Acknowledge failed:', err.message);
  }
}

if (payloads.length === 0) {
  return [{ json: { __skip: true, message: 'No payloads — already handled by another execution' } }];
}

// Collect unique record IDs from payloads
const recordMap = new Map();

for (const payload of payloads) {
  const changedTablesObj = payload?.changedTablesById || {};
  for (const [tableId, tableChanges] of Object.entries(changedTablesObj)) {
    const cfg = TABLE_CONFIG.find(t => t.sourceTableId === tableId);
    if (!cfg) continue;

    const createdIds = Object.keys(tableChanges?.createdRecordsById || {});
    const updatedIds = Object.keys(tableChanges?.changedRecordsById || {});

    for (const id of createdIds) {
      if (!recordMap.has(id)) recordMap.set(id, { cfg, type: 'created' });
    }
    for (const id of updatedIds) {
      if (!recordMap.has(id)) recordMap.set(id, { cfg, type: 'updated' });
    }
  }
}

if (recordMap.size === 0) {
  return [{ json: { __skip: true, message: 'No matching tables changed' } }];
}

// ============================================================
// Wait 30 seconds for user to finish filling all fields
// ============================================================
await new Promise(resolve => setTimeout(resolve, 30000));

const results = [];

for (const [recordId, { cfg, type }] of recordMap.entries()) {

  // ============================================================
  // API CALL 3 — Fetch the latest complete record from source
  // ============================================================
  let recordData;
  try {
    recordData = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.airtable.com/v0/${cfg.sourceBaseId}/${cfg.sourceTableId}/${recordId}`,
      headers: { 'Authorization': `Bearer ${AIRTABLE_TOKEN}` },
      json: true
    });
  } catch (err) {
    results.push({ json: { status: 'fetch_failed', record: recordId, error: err.message } });
    continue;
  }

  const sourceFields = recordData.fields || {};
  const fieldsToWrite = {};

  for (const fieldName of cfg.fields) {
    if (sourceFields[fieldName] !== undefined) {
      fieldsToWrite[fieldName] = sourceFields[fieldName];
    }
  }

  fieldsToWrite['_original_record_id'] = recordId;
  fieldsToWrite['_synced_at'] = new Date().toISOString().replace('T', ' ').substring(0, 19);

  // ============================================================
  // API CALL 4 — Upsert into backup (creates OR updates)
  // ============================================================
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `https://api.airtable.com/v0/${cfg.backupBaseId}/${cfg.backupTableId}`,
      headers: {
        'Authorization': `Bearer ${AIRTABLE_TOKEN}`,
        'Content-Type': 'application/json'
      },
      body: {
        performUpsert: {
          fieldsToMergeOn: ['_original_record_id']
        },
        records: [{ fields: fieldsToWrite }]
      },
      json: true
    });

    results.push({
      json: {
        status: type,
        record: recordId,
        table: cfg.tableLabel,
        fields: fieldsToWrite
      }
    });

    console.log(`✅ ${type} record ${recordId} in ${cfg.tableLabel}`);

  } catch (err) {
    results.push({ json: { status: 'upsert_failed', record: recordId, error: err.message } });
  }
}

return results.length > 0
  ? results
  : [{ json: { __skip: true, message: 'Nothing to sync' } }];

// Just log the skipped result
const item = $input.first().json;
console.log('Skipped:', item.message);
return [{ json: { status: 'skipped', message: item.message } }];

// Log successful sync results
const items = $input.all();
const summary = items.map(i => ({
  table: i.json.table,
  record: i.json.record,
  status: i.json.status
}));
console.log('Sync complete:', JSON.stringify(summary, null, 2));
return items;
